body:
  // Toggle selection - if already selected, deselect
  if (selectedAgent && selectedAgent.path === agent.path) {
    selectedAgent$.set(null);
  } else {
    selectedAgent$.set(agent);
  }
  onSelectAgent?.(agent);
}

  // Force refresh by appending a dummy parameter if URL is unchanged
  setCurrentUrl(
    inputValue === currentUrl
      ? `${inputValue}${inputValue.includes('?') ? '&' : '?'}_refresh=${Date.now()}`
      : inputValue
  );
  setLogs([]); // Clear logs on refresh
}

  if (event.data?.type === 'console') {
    setLogs((prev) => [
      ...prev,
      {
        level: event.data.level,
        args: event.data.args,
        timestamp: Date.now(),
      },
    ]);
  }
}

  const iframe = iframeRef.current;
  if (iframe?.contentWindow) {
    // Use Function constructor instead of eval for better type safety
    const script = new Function(consoleProxyScript);
    iframe.contentWindow.document.head.appendChild(
      Object.assign(iframe.contentWindow.document.createElement('script'), {
        textContent: `(${script.toString()})();`,
      })
    );
  }
}

  setSelectedWorkspace(workspace);
  setWorkspaceExplicitlySelected(workspace !== '.');
}

  e.preventDefault();
  if (isGenerating) {
    // If there's a message, queue it instead of interrupting
    if (message.trim()) {
      console.log('[ChatInput] Queueing message for after generation completes');
      // Capture options at queue time to preserve user's intent
      setQueuedMessage({
        text: message,
        options: {
          model: effectiveModel === 'default' ? undefined : effectiveModel,
          stream: streamingEnabled,
          workspace: selectedWorkspace || undefined,
        },
      });
      setMessage('');
      // Clear localStorage draft since we're queueing it
      if (typeof window !== 'undefined') {
        localStorage.removeItem(storageKey);
      }
      // Reset textarea height
      if (textareaRef.current) {
        textareaRef.current.style.height = '';
      }
    } else if (onInterrupt) {
      // No message text, so interrupt
      console.log('[ChatInput] Interrupting generation...', { isGenerating });
      try {
        await onInterrupt();
        console.log('[ChatInput] Generation interrupted successfully', { isGenerating });
      } catch (error) {
        console.error('[ChatInput] Error interrupting generation:', error);
      }
    }
  } else if (message.trim()) {
    onSend(message, {
      model: effectiveModel === 'default' ? undefined : effectiveModel,
      stream: streamingEnabled,
      workspace: selectedWorkspace || undefined,
    });
    setMessage('');
    // Reset textarea height to default by removing inline style
    if (textareaRef.current) {
      textareaRef.current.style.height = '';
    }
  }
}

  // Handle file autocomplete keyboard navigation first
  if (fileAutocomplete.state.isOpen) {
    const handled = fileAutocomplete.handleKeyDown(e);
    if (handled) {
      // If Tab or Enter was pressed with a selection, apply it
      if (
        (e.key === 'Tab' || e.key === 'Enter') &&
        fileAutocomplete.state.files[fileAutocomplete.state.selectedIndex]
      ) {
        const newValue = fileAutocomplete.selectFile(
          fileAutocomplete.state.files[fileAutocomplete.state.selectedIndex]
        );
        setMessage(newValue);
      }
      return;
    }
  }

  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    handleSubmit(e);
  } else if (e.key === 'Escape') {
    e.preventDefault();
    e.stopPropagation();

    // If autocomplete is open, close it first
    if (fileAutocomplete.state.isOpen) {
      fileAutocomplete.close();
      return;
    }

    // If generating, interrupt
    if (isGenerating && onInterrupt) {
      console.log('[ChatInput] Escape pressed, interrupting generation...');
      onInterrupt();
    }

    // Always blur the input on Escape
    textareaRef.current?.blur();
  }
}

  const newValue = e.target.value;
  const cursorPos = e.target.selectionStart || 0;
  setMessage(newValue);
  // Auto-adjust height
  e.target.style.height = 'auto';
  e.target.style.height = `${Math.min(e.target.scrollHeight, 400)}px`;
  // Update file autocomplete
  fileAutocomplete.handleInputChange(newValue, cursorPos);
}

  if (!message$.files.get()?.length) return null;

  return (
    <div className="mt-2 space-y-2">
      <Memo>
        {() => {
          return message$.files.map((filename$) => {
            // Remove any parent directory references and normalize path
            const filename = filename$.get();
            const sanitizedPath = filename
              .split('/')
              .filter((part) => part !== '..')
              .join('/');
            const fileUrl = `${connectionConfig.baseUrl}/api/conversations/${conversationId}/files/${sanitizedPath}`;
            const isImage = /\.(jpg|jpeg|png|gif|webp)$/i.test(filename);

            // Get just the filename without path for display
            const displayName = sanitizedPath.split('/').pop() || sanitizedPath;

            if (isImage) {
              return (
                <div key={filename} className="max-w-md">
                  <a
                    href={fileUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="block cursor-zoom-in"
                    title="Click to view full size"
                  >
                    <div className="relative">
                      <img
                        src={fileUrl}
                        alt={displayName}
                        className="rounded-md border border-border transition-opacity hover:opacity-90"
                        onError={(e) => {
                          const img = e.currentTarget;
                          const errorDiv = img.parentElement?.querySelector('.error-message');
                          if (errorDiv) {
                            if (img.src.includes('..')) {
                              errorDiv.textContent =
                                '⚠️ Cannot access files outside the workspace';
                            } else {
                              errorDiv.textContent = '⚠️ Failed to load image';
                            }
                            errorDiv.classList.remove('hidden');
                          }
                          img.classList.add('hidden');
                        }}
                      />
                      <div className="error-message hidden rounded-md border border-red-200 bg-red-50 p-4 text-sm text-red-600 dark:border-red-800 dark:bg-red-900/20 dark:text-red-400"></div>
                    </div>
                  </a>
                  <div className="mt-1 text-xs text-muted-foreground">{displayName}</div>
                </div>
              );
            }

            return (
              <div key={filename} className="text-sm">
                <a
                  href={fileUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-500 hover:underline"
                >
                  📎 {displayName}
                </a>
              </div>
            );
          });
        }}
      </Memo>
    </div>
  );
}

  const [copied, setCopied] = useState(false);
  const [highlightedCode, setHighlightedCode] = useState('');

  useEffect(() => {
    if (!code) return;

    // Use our shared utility
    setHighlightedCode(highlightCode(code, language, true, 1000).code);
  }, [code, language]);

  if (!code) return null;

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const lines = code.split('\n');

  return (
    <div className="relative overflow-hidden rounded bg-muted">
      <div className="absolute right-1 z-10">
        <Button
          variant="ghost"
          size="sm"
          onClick={handleCopy}
          className="h-10 w-10 p-1 opacity-50 hover:opacity-100"
        >
          {copied ? <Check size={16} /> : <Clipboard className="drop-shadow-md" size={16} />}
        </Button>
      </div>

      {/* Single scrollable container for both line numbers and code */}
      <div className="overflow-auto text-xs" style={{ maxHeight }}>
        <div className="flex">
          {showLineNumbers && lines.length > 1 && (
            <div className="min-w-12 flex-none select-none border-r border-muted-foreground/20 bg-muted/50 pr-1 text-right font-mono text-muted-foreground">
              {lines.map((_, i) => (
                <div key={i} className="px-2 text-xs leading-6">
                  {i + 1}
                </div>
              ))}
            </div>
          )}

          <div className="flex-1">
            {highlightedCode ? (
              <pre className="whitespace-pre px-4 leading-6">
                <code dangerouslySetInnerHTML={{ __html: highlightedCode }} />
              </pre>
            ) : (
              <pre className="whitespace-pre px-4 leading-6">{code}</pre>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

  navigator.clipboard.writeText(code);
  setCopied(true);
  setTimeout(() => setCopied(false), 2000);
}

  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState('');
  const navigate = useNavigate();

  // Toggle command palette with Cmd+K or Ctrl+K
  useEffect(() => {
    const down = (e: KeyboardEvent) => {
      if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        setOpen((open) => !open);
      }
    };

    document.addEventListener('keydown', down);
    return () => document.removeEventListener('keydown', down);
  }, []);

  // Reset search when closing
  useEffect(() => {
    if (!open) {
      setSearch('');
    }
  }, [open]);

  // Define available actions
  const actions = useMemo<CommandAction[]>(
    () => [
      {
        id: 'new-conversation',
        label: 'New Conversation',
        description: 'Start a new chat',
        icon: <Plus className="mr-2 h-4 w-4" />,
        keywords: ['new', 'chat', 'conversation', 'create'],
        action: () => {
          navigate('/');
          setOpen(false);
        },
        group: 'Actions',
      },
      {
        id: 'search-conversations',
        label: 'Search Conversations',
        description: 'Find past chats',
        icon: <Search className="mr-2 h-4 w-4" />,
        keywords: ['search', 'find', 'conversations', 'history'],
        action: () => {
          // TODO: Implement search modal
          console.log('Search conversations');
          setOpen(false);
        },
        group: 'Actions',
      },
      {
        id: 'create-agent',
        label: 'Create Agent',
        description: 'Set up a new AI agent',
        icon: <Sparkles className="mr-2 h-4 w-4" />,
        keywords: ['agent', 'create', 'new', 'ai'],
        action: () => {
          navigate('/agents');
          setOpen(false);
        },
        group: 'Actions',
      },
      {
        id: 'settings',
        label: 'Settings',
        description: 'Configure application',
        icon: <Settings className="mr-2 h-4 w-4" />,
        keywords: ['settings', 'preferences', 'config'],
        action: () => {
          navigate('/settings');
          setOpen(false);
        },
        group: 'Navigation',
      },
      {
        id: 'home',
        label: 'Home',
        description: 'Go to home page',
        icon: <Home className="mr-2 h-4 w-4" />,
        keywords: ['home', 'main'],
        action: () => {
          navigate('/');
          setOpen(false);
        },
        group: 'Navigation',
      },
      {
        id: 'workspaces',
        label: 'Workspaces',
        description: 'Manage workspaces',
        icon: <FileText className="mr-2 h-4 w-4" />,
        keywords: ['workspace', 'folder', 'project'],
        action: () => {
          navigate('/workspaces');
          setOpen(false);
        },
        group: 'Navigation',
      },
      {
        id: 'agents',
        label: 'Agents',
        description: 'View all agents',
        icon: <Users className="mr-2 h-4 w-4" />,
        keywords: ['agents', 'list', 'view'],
        action: () => {
          navigate('/agents');
          setOpen(false);
        },
        group: 'Navigation',
      },
    ],
    [navigate]
  );

  // Filter actions based on search query with performance optimization
  const filteredActions = useMemo(() => {
    if (!search) return actions;

    const searchLower = search.toLowerCase();
    return actions.filter((action) => {
      // Search in label
      if (action.label.toLowerCase().includes(searchLower)) return true;
      // Search in description
      if (action.description?.toLowerCase().includes(searchLower)) return true;
      // Search in keywords
      return action.keywords.some((keyword) => keyword.toLowerCase().includes(searchLower));
    });
  }, [search, actions]);

  // Group filtered actions by category
  const groupedActions = useMemo(() => {
    const groups = new Map<string, CommandAction[]>();
    filteredActions.forEach((action) => {
      const group = groups.get(action.group) || [];
      group.push(action);
      groups.set(action.group, group);
    });
    return Array.from(groups.entries());
  }, [filteredActions]);

  // Handle action execution with useCallback for performance
  const handleSelect = useCallback((action: CommandAction) => {
    action.action();
  }, []);

  return (
    <CommandDialog open={open} onOpenChange={setOpen}>
      <CommandInput
        placeholder="Type a command or search..."
        value={search}
        onValueChange={setSearch}
      />
      <CommandList>
        <CommandEmpty>No results found.</CommandEmpty>
        {groupedActions.map(([groupName, groupActions], index) => (
          <div key={groupName}>
            {index > 0 && <CommandSeparator />}
            <CommandGroup heading={groupName}>
              {groupActions.map((action) => (
                <CommandItem
                  key={action.id}
                  value={action.id}
                  onSelect={() => handleSelect(action)}
                >
                  {action.icon}
                  <div className="flex flex-col">
                    <span>{action.label}</span>
                    {action.description && (
                      <span className="text-xs text-muted-foreground">{action.description}</span>
                    )}
                  </div>
                </CommandItem>
              ))}
            </CommandGroup>
          </div>
        ))}
      </CommandList>
    </CommandDialog>
  );
}

  if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
    e.preventDefault();
    setOpen((open) => !open);
  }
}

  navigator.clipboard.writeText(serverCommand);
  toast.success('Command copied to clipboard');
}

  const value = e.target.value;
  if (value && value.startsWith('Bearer ')) {
    const token = value.replace('Bearer ', '');
    setFormState((prev) => ({ ...prev, authToken: token }));
    toast('Detected "Bearer" prefix, it is now automatically removed', {
      description: 'Token format updated',
    });
    return;
  }
  setFormState((prev) => ({ ...prev, authToken: value }));
}

  try {
    await connect({
      baseUrl: formState.baseUrl,
      authToken: formState.useAuthToken ? formState.authToken : null,
      useAuthToken: formState.useAuthToken,
    });
    setOpen(false);
  } catch (error) {
    // Error handling is now done in the ApiContext
    console.error('Connection error:', error);
  }
}

  // Only handle 'i' key when:
  // - Not in an input/textarea
  // - Not in read-only mode
  // - Has an active session
  if (
    e.key === 'i' &&
    !isReadOnly &&
    hasSession$.get() &&
    !(e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement)
  ) {
    e.preventDefault();
    shouldFocus$.set(true);
  }
}

  if (scrollContainerRef.current) {
    isAutoScrolling$.set(true);
    scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    requestAnimationFrame(() => {
      isAutoScrolling$.set(false);
    });
  }
}

  const match = name.match(/^\d{4}-\d{2}-\d{2}[- ](.*)/);
  return match ? match[1] : name;
}

  if (demoConv) {
    const messages = getDemoMessages(demoConv.id);
    return messages.reduce((acc: MessageBreakdown, msg) => {
      acc[msg.role] = (acc[msg.role] || 0) + 1;
      return acc;
    }, {});
  }

  // Get messages from store
  const storeConv = conversations$.get(conv.id)?.get();
  // Return empty breakdown if conversation or data is not loaded yet
  if (!storeConv?.data?.log) return {};

  return storeConv.data.log.reduce((acc: MessageBreakdown, msg$) => {
    const role = msg$.role;
    if (role && typeof role === 'string') {
      acc[role as MessageRole] = (acc[role as MessageRole] || 0) + 1;
    }
    return acc;
  }, {} as MessageBreakdown);
}

  const order: MessageRole[] = ['user', 'assistant', 'system', 'tool'];
  return Object.entries(breakdown)
    .sort(([a], [b]) => {
      const aIndex = order.indexOf(a as MessageRole);
      const bIndex = order.indexOf(b as MessageRole);
      if (aIndex === -1 && bIndex === -1) return 0;
      if (aIndex === -1) return 1;
      if (bIndex === -1) return -1;
      return aIndex - bIndex;
    })
    .map(([role, count]) => `${role}: ${count}`)
    .join('\n');
}

  if (!data.name.trim() || !data.template_repo.trim() || !data.template_branch.trim()) {
    return;
  }

  // Generate fork_command if not explicitly set
  const processedData = { ...data };
  if (!processedData.fork_command.trim()) {
    processedData.fork_command = `./fork.sh ${processedData.path} ${processedData.name}`;
  }

  setIsLoading(true);
  try {
    const response = await onAgentCreated(processedData);

    // Reset form
    form.reset();
    onOpenChange(false);

    toast.success('Agent created successfully!');

    // Refresh conversations data to include the new conversation
    await queryClient.invalidateQueries({ queryKey: ['conversations'] });

    // Set selected agent
    selectedAgent$.set({
      name: data.name,
      path: response.agent_path,
      description: `Agent: ${data.name}`,
      conversationCount: 0,
      lastUsed: new Date().toISOString(),
    });

    // Navigate and force a refresh if needed
    const conversationId = response.initial_conversation_id;
    navigate(`/chat/${conversationId}`);
  } catch (error) {
    console.error('Error creating agent:', error);

    let errorMessage = 'Failed to create agent. Please try again.';

    if (ApiClientError.isApiError(error)) {
      // Extract the actual error message from the server response
      errorMessage = `Failed to create agent: ${error.message}`;
    } else if (error instanceof Error) {
      errorMessage = `Failed to create agent: ${error.message}`;
    }

    toast.error(errorMessage, {
      duration: 10000, // Show error longer so user can read it
      style: {
        maxWidth: '500px',
      },
    });
  } finally {
    setIsLoading(false);
  }
}

  const { deleteConversation, connectionConfig, isConnected$ } = useApi();
  const queryClient = useQueryClient();
  const isConnected = use$(isConnected$);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isError, setIsError] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const handleDelete = async () => {
    // Show loading indicator
    setIsDeleting(true);

    // Delete conversation
    try {
      await deleteConversation(conversationName);
    } catch (error) {
      setIsError(true);
      if (error instanceof Error) {
        setErrorMessage(error.message);
      } else {
        setErrorMessage('An unknown error occurred');
      }
      setIsDeleting(false);
      return;
    }
    conversations$.delete(conversationName);
    queryClient.invalidateQueries({
      queryKey: ['conversations', connectionConfig.baseUrl, isConnected],
    });
    selectedConversation$.set(demoConversations[0].name);

    // Reset state
    await onDelete();
    setIsDeleting(false);
    onOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Delete Conversation</DialogTitle>
          <DialogDescription>
            Are you sure you want to delete the conversation <strong>{conversationName}</strong>?
            This action cannot be undone.
          </DialogDescription>
        </DialogHeader>
        {isError && (
          <div className="mb-4 rounded-md bg-destructive/10 p-4 text-sm text-destructive">
            <p>{errorMessage}</p>
          </div>
        )}
        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button variant="destructive" onClick={handleDelete} disabled={isDeleting}>
            {isDeleting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            Delete
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

  // Show loading indicator
  setIsDeleting(true);

  // Delete conversation
  try {
    await deleteConversation(conversationName);
  } catch (error) {
    setIsError(true);
    if (error instanceof Error) {
      setErrorMessage(error.message);
    } else {
      setErrorMessage('An unknown error occurred');
    }
    setIsDeleting(false);
    return;
  }
  conversations$.delete(conversationName);
  queryClient.invalidateQueries({
    queryKey: ['conversations', connectionConfig.baseUrl, isConnected],
  });
  selectedConversation$.set(demoConversations[0].name);

  // Reset state
  await onDelete();
  setIsDeleting(false);
  onOpenChange(false);
}

  onExampleSelect(example);
  setIsModalOpen(false);
}

  const [editedContent, setEditedContent] = useState('');
  const [isEditing, setIsEditing] = useState(false);
  const [confirmLoading, setConfirmLoading] = useState(false);
  const [customCount, setCustomCount] = useState(10);
  const [showCustomInput, setShowCustomInput] = useState(false);
  const pendingTool = use$(pendingTool$);

  // Reset state when the pending tool changes
  React.useEffect(() => {
    if (pendingTool) {
      const content = pendingTool.tooluse.content;
      setEditedContent(content);
      setIsEditing(false);
      setConfirmLoading(false);
      setShowCustomInput(false);
    }
  }, [pendingTool]);

  const handleConfirm = React.useCallback(async () => {
    setConfirmLoading(true);
    try {
      await onConfirm();
    } catch (error) {
      console.error('Error confirming tool:', error);
    } finally {
      setConfirmLoading(false);
    }
  }, [onConfirm]);

  // Add keyboard handler for Enter key
  React.useEffect(() => {
    const handleKeyPress = async (e: KeyboardEvent) => {
      if (
        pendingTool &&
        !isEditing &&
        e.key === 'Enter' &&
        !e.shiftKey &&
        !e.ctrlKey &&
        !e.altKey
      ) {
        e.preventDefault();
        await handleConfirm();
      }
    };

    window.addEventListener('keypress', handleKeyPress);
    return () => window.removeEventListener('keypress', handleKeyPress);
  }, [pendingTool, isEditing, handleConfirm]);

  const handleEdit = async () => {
    setConfirmLoading(true);
    try {
      await onEdit(editedContent);
    } catch (error) {
      console.error('Error confirming edited tool:', error);
    } finally {
      setConfirmLoading(false);
    }
  };

  const handleSkip = async () => {
    try {
      await onSkip();
    } catch (error) {
      console.error('Error skipping tool:', error);
    }
  };

  // Format args for display
  const formatArgs = (args: string[]) => {
    if (!args || args.length === 0) return 'No arguments';
    if (args.length === 1) return args[0];
    return args.map((arg, i) => `${i + 1}. ${arg}`).join('\n');
  };

  if (!pendingTool) return null;

  return (
    <div className="role-system mb-4 mt-4">
      <div className="mx-auto max-w-3xl px-4">
        <div className="relative">
          <MessageAvatar
            role$={observable('system' as const)}
            isError$={observable(false)}
            isSuccess$={observable(false)}
            chainType$={observable('standalone' as const)}
          />
          <div className="md:px-12">
            <div className="rounded-lg border border-amber-200 bg-amber-50 dark:border-amber-800 dark:bg-amber-950/20">
              <div className="border-b border-amber-200 px-4 py-3 dark:border-amber-800">
                <div className="flex items-center gap-2">
                  <Settings className="h-4 w-4 text-amber-600 dark:text-amber-400" />
                  <h3 className="font-medium text-amber-800 dark:text-amber-200">
                    Tool Execution Confirmation
                  </h3>
                </div>

                <p className="mt-1 text-sm text-amber-700 dark:text-amber-300">
                  The assistant wants to use
                  <code className="rounded bg-muted px-2 py-1 font-mono text-sm">
                    {pendingTool.tooluse.tool}
                  </code>
                </p>
              </div>

              <div className="space-y-4 p-4">
                {/* Arguments */}
                {pendingTool.tooluse.args.length > 0 && (
                  <div className="space-y-2">
                    <span className="text-sm font-medium text-muted-foreground">Arguments:</span>
                    <CodeDisplay
                      code={formatArgs(pendingTool.tooluse.args)}
                      maxHeight="120px"
                      showLineNumbers={false}
                    />
                  </div>
                )}

                {/* Code */}
                <div className="space-y-2">
                  {isEditing ? (
                    <Textarea
                      value={editedContent}
                      onChange={(e) => setEditedContent(e.target.value)}
                      rows={Math.min(12, editedContent.split('\n').length + 2)}
                      className="resize-none font-mono text-sm"
                      placeholder="Edit the code to be executed..."
                    />
                  ) : (
                    <CodeDisplay
