  switch (type) {
    case 'image':
      return ImageIcon;
    case 'video':
      return FileVideoIcon;
    case 'audio':
      return FileAudioIcon;
    case 'text':
      return FileTextIcon;
    case 'application':
      switch (subtype) {
        case 'x-archive':
        case 'zip':
        case 'x-tar':
        case 'x-gzip':
          return FileArchiveIcon;
        case 'x-httpd-php':
        case 'javascript':
        case 'typescript':
          return FileCodeIcon;
        default:
          if (subtype.includes('code') || subtype.includes('script')) {
            return FileCodeIcon;
          }
      }
  }

